const questionnaireHtml = "<!doctype html>\n<html lang=\"he\" dir=\"rtl\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>שאלון אפיון למערכת הזמנות</title>\n  <style>\n    :root {\n      color-scheme: light;\n      --bg: #f6f7f8;\n      --panel: #ffffff;\n      --ink: #17202a;\n      --muted: #64707d;\n      --line: #dfe5eb;\n      --accent: #1c7c54;\n      --accent-dark: #145c3e;\n      --warn: #8a5a00;\n    }\n\n    * {\n      box-sizing: border-box;\n    }\n\n    body {\n      margin: 0;\n      font-family: Arial, \"Helvetica Neue\", sans-serif;\n      background: var(--bg);\n      color: var(--ink);\n      line-height: 1.55;\n    }\n\n    main {\n      width: min(920px, calc(100% - 28px));\n      margin: 0 auto;\n      padding: 28px 0 42px;\n    }\n\n    header {\n      margin-bottom: 22px;\n    }\n\n    h1 {\n      margin: 0 0 8px;\n      font-size: 30px;\n      line-height: 1.2;\n    }\n\n    .intro {\n      margin: 0;\n      color: var(--muted);\n      font-size: 16px;\n    }\n\n    form {\n      display: grid;\n      gap: 14px;\n    }\n\n    section {\n      background: var(--panel);\n      border: 1px solid var(--line);\n      border-radius: 8px;\n      padding: 18px;\n    }\n\n    h2 {\n      margin: 0 0 14px;\n      font-size: 20px;\n    }\n\n    label {\n      display: block;\n      font-weight: 700;\n      margin-bottom: 7px;\n    }\n\n    .field {\n      margin-bottom: 16px;\n    }\n\n    .field:last-child {\n      margin-bottom: 0;\n    }\n\n    input,\n    textarea,\n    select {\n      width: 100%;\n      border: 1px solid #cfd8e3;\n      border-radius: 7px;\n      padding: 11px 12px;\n      font: inherit;\n      color: var(--ink);\n      background: #fff;\n    }\n\n    textarea {\n      min-height: 92px;\n      resize: vertical;\n    }\n\n    .choices {\n      display: grid;\n      gap: 8px;\n    }\n\n    .choice {\n      display: flex;\n      align-items: flex-start;\n      gap: 9px;\n      padding: 9px 10px;\n      border: 1px solid var(--line);\n      border-radius: 7px;\n      background: #fbfcfd;\n      font-weight: 400;\n    }\n\n    .choice input {\n      width: auto;\n      margin-top: 4px;\n    }\n\n    .hint {\n      margin-top: 6px;\n      color: var(--muted);\n      font-size: 13px;\n    }\n\n    .actions {\n      position: sticky;\n      bottom: 0;\n      display: flex;\n      flex-wrap: wrap;\n      gap: 10px;\n      padding: 12px 0 0;\n      background: linear-gradient(to top, var(--bg) 70%, rgba(246, 247, 248, 0));\n    }\n\n    button {\n      border: 0;\n      border-radius: 7px;\n      padding: 11px 16px;\n      font: inherit;\n      font-weight: 700;\n      cursor: pointer;\n    }\n\n    .primary {\n      background: var(--accent);\n      color: #fff;\n    }\n\n    .primary:hover {\n      background: var(--accent-dark);\n    }\n\n    .secondary {\n      background: #e7ecef;\n      color: var(--ink);\n    }\n\n    .notice {\n      display: none;\n      margin-top: 10px;\n      color: var(--accent-dark);\n      font-weight: 700;\n    }\n\n    .warning {\n      color: var(--warn);\n    }\n\n    @media (max-width: 640px) {\n      main {\n        width: min(100% - 18px, 920px);\n        padding-top: 18px;\n      }\n\n      h1 {\n        font-size: 24px;\n      }\n\n      section {\n        padding: 14px;\n      }\n\n      .actions {\n        display: grid;\n      }\n    }\n  </style>\n</head>\n<body>\n  <main>\n    <header>\n      <h1>שאלון קצר לאפיון מערכת הזמנות</h1>\n      <p class=\"intro\">המטרה היא להבין איך העסק עובד היום, כדי לבנות מערכת CRM והזמנות שמתאימה בפועל לעבודה היומיומית.</p>\n    </header>\n\n    <form id=\"questionnaire\">\n      <section>\n        <h2>פרטי העסק</h2>\n        <div class=\"field\">\n          <label for=\"businessName\">שם העסק</label>\n          <input id=\"businessName\" name=\"שם העסק\" autocomplete=\"organization\">\n        </div>\n        <div class=\"field\">\n          <label for=\"contactName\">שם איש קשר</label>\n          <input id=\"contactName\" name=\"שם איש קשר\" autocomplete=\"name\">\n        </div>\n        <div class=\"field\">\n          <label for=\"contactPhone\">טלפון</label>\n          <input id=\"contactPhone\" name=\"טלפון\" autocomplete=\"tel\">\n        </div>\n      </section>\n\n      <section>\n        <h2>היקף פעילות</h2>\n        <div class=\"field\">\n          <label for=\"customerCount\">כמה לקוחות קיימים יש בערך?</label>\n          <input id=\"customerCount\" name=\"כמות לקוחות קיימים\" placeholder=\"לדוגמה: 200 / 800 / לא יודע\">\n        </div>\n        <div class=\"field\">\n          <label for=\"ordersCount\">כמה הזמנות יש בערך ביום או בשבוע?</label>\n          <input id=\"ordersCount\" name=\"כמות הזמנות\" placeholder=\"לדוגמה: 10 ביום / 60 בשבוע\">\n        </div>\n        <div class=\"field\">\n          <label for=\"productCount\">כמה מוצרים / שקים שונים יש בערך בקטלוג?</label>\n          <input id=\"productCount\" name=\"כמות מוצרים\" placeholder=\"לדוגמה: 40 / 150 / לא יודע\">\n        </div>\n      </section>\n\n      <section>\n        <h2>לקוחות והזמנות</h2>\n        <div class=\"field\">\n          <label>האם לקוח יכול להזמין כמה מוצרים באותה הזמנה?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"כמה מוצרים בהזמנה\" value=\"כן\"> כן</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"כמה מוצרים בהזמנה\" value=\"לא, בדרך כלל מוצר אחד\"> לא, בדרך כלל מוצר אחד</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"כמה מוצרים בהזמנה\" value=\"לא בטוח\"> לא בטוח</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"manualOrders\">באילו מקרים בעל העסק יפתח הזמנה ידנית?</label>\n          <textarea id=\"manualOrders\" name=\"מקרים להזמנה ידנית\" placeholder=\"לדוגמה: לקוחות מבוגרים, הזמנות טלפוניות, לקוח שלא מסתדר עם האתר\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"specialCustomers\">האם יש לקוחות עם תנאים מיוחדים?</label>\n          <textarea id=\"specialCustomers\" name=\"לקוחות עם תנאים מיוחדים\" placeholder=\"לדוגמה: מחיר קבוע, הנחה, תשלום אחרי אספקה, חוב פתוח\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>קטלוג ומחירים</h2>\n        <div class=\"field\">\n          <label>איך נכון להציג מוצרים?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"מבנה קטלוג\" value=\"מותג/סדרה ואז בחירת סוג, טעם ומשקל\"> מותג/סדרה ואז בחירת סוג, טעם ומשקל</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מבנה קטלוג\" value=\"רשימת שקים נפרדים\"> רשימת שקים נפרדים</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מבנה קטלוג\" value=\"לא משנה לי\"> לא משנה לי</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"priceRules\">איך מחירים מיוחדים והנחות עובדים היום?</label>\n          <textarea id=\"priceRules\" name=\"כללי מחירים והנחות\" placeholder=\"לדוגמה: יש לקוחות עם מחיר קבוע, מבצעים לפי מוצר, הנחות לפי לקוח\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"substitutes\">האם יש מוצרים תחליפיים כשמוצר חסר?</label>\n          <textarea id=\"substitutes\" name=\"מוצרים תחליפיים\" placeholder=\"לדוגמה: אם אין עוף מציעים כבש, אם אין 12 קג מציעים 2 של 6 קג\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>משלוחים</h2>\n        <div class=\"field\">\n          <label>איך החלוקה מתבצעת היום?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"לפי ימים קבועים\"> לפי ימים קבועים</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"לפי אזורים\"> לפי אזורים</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"לפי עיר/שכונה\"> לפי עיר/שכונה</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"שיטת חלוקה\" value=\"ידנית לפי מה שנוח\"> ידנית לפי מה שנוח</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"deliveryDays\">האם יש ימי חלוקה קבועים?</label>\n          <input id=\"deliveryDays\" name=\"ימי חלוקה קבועים\" placeholder=\"לדוגמה: ראשון ושלישי באזור המרכז\">\n        </div>\n        <div class=\"field\">\n          <label for=\"deliveryAreas\">אילו אזורים / ערים העסק משרת?</label>\n          <textarea id=\"deliveryAreas\" name=\"אזורי שירות\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label>האם לקוח צריך לבחור מועד אספקה?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"בחירת מועד אספקה\" value=\"כן, הלקוח בוחר מועד זמין\"> כן, הלקוח בוחר מועד זמין</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"בחירת מועד אספקה\" value=\"לא, העסק קובע ומעדכן\"> לא, העסק קובע ומעדכן</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"בחירת מועד אספקה\" value=\"לא בטוח\"> לא בטוח</label>\n          </div>\n          <div class=\"hint\">כרגע ידוע שצריך התראה של יומיים מראש.</div>\n        </div>\n      </section>\n\n      <section>\n        <h2>תשלומים וחשבוניות</h2>\n        <div class=\"field\">\n          <label>אילו אמצעי תשלום קיימים בפועל?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"קישור תשלום משולם\"> קישור תשלום משולם</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"bit דרך משולם\"> bit דרך משולם</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"Google Pay דרך משולם\"> Google Pay דרך משולם</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"מזומן לשליח\"> מזומן לשליח</label>\n            <label class=\"choice\"><input type=\"checkbox\" name=\"אמצעי תשלום\" value=\"העברה בנקאית\"> העברה בנקאית</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"cashInvoice\">איך מפיקים חשבונית / קבלה על מזומן לשליח?</label>\n          <textarea id=\"cashInvoice\" name=\"חשבונית על מזומן לשליח\" placeholder=\"לדוגמה: דרך משולם ידנית, אחרי שהשליח חוזר, דרך מערכת אחרת\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"failedPayments\">מה עושים היום עם לקוח שלא שילם?</label>\n          <textarea id=\"failedPayments\" name=\"טיפול באי תשלום\" placeholder=\"לדוגמה: מתקשרים אליו, לא מוציאים משלוח, מסמנים חוב\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>עבודה יומיומית</h2>\n        <div class=\"field\">\n          <label>איפה בעל העסק יעבוד עם המערכת בעיקר?</label>\n          <div class=\"choices\">\n            <label class=\"choice\"><input type=\"radio\" name=\"מכשיר עבודה עיקרי\" value=\"טלפון\"> טלפון</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מכשיר עבודה עיקרי\" value=\"מחשב\"> מחשב</label>\n            <label class=\"choice\"><input type=\"radio\" name=\"מכשיר עבודה עיקרי\" value=\"גם וגם\"> גם וגם</label>\n          </div>\n        </div>\n        <div class=\"field\">\n          <label for=\"currentPain\">מה הכי מפריע היום בהתנהלות הקיימת?</label>\n          <textarea id=\"currentPain\" name=\"כאבים עיקריים היום\"></textarea>\n        </div>\n        <div class=\"field\">\n          <label for=\"success\">מה ייחשב הצלחה מבחינתך אחרי חודש שימוש?</label>\n          <textarea id=\"success\" name=\"מדד הצלחה אחרי חודש\"></textarea>\n        </div>\n      </section>\n\n      <section>\n        <h2>הערות נוספות</h2>\n        <div class=\"field\">\n          <label for=\"notes\">כל דבר נוסף שחשוב שנדע</label>\n          <textarea id=\"notes\" name=\"הערות נוספות\"></textarea>\n        </div>\n      </section>\n\n      <div class=\"actions\">\n        <button class=\"primary\" type=\"button\" id=\"copyAnswers\">העתקת התשובות</button>\n        <button class=\"secondary\" type=\"button\" id=\"downloadAnswers\">הורדת קובץ תשובות</button>\n        <button class=\"secondary\" type=\"reset\">ניקוי הטופס</button>\n      </div>\n      <div class=\"notice\" id=\"notice\">התשובות הועתקו. אפשר להדביק אותן בוואטסאפ או במייל.</div>\n      <p class=\"hint warning\">הטופס לא שולח מידע לשרת. אחרי המילוי יש ללחוץ על העתקת התשובות או הורדת קובץ.</p>\n    </form>\n  </main>\n\n  <script>\n    const form = document.getElementById('questionnaire');\n    const notice = document.getElementById('notice');\n\n    function collectAnswers() {\n      const data = new FormData(form);\n      const grouped = {};\n\n      for (const [key, value] of data.entries()) {\n        if (!value || !String(value).trim()) continue;\n        if (!grouped[key]) grouped[key] = [];\n        grouped[key].push(String(value).trim());\n      }\n\n      const lines = ['שאלון אפיון מערכת הזמנות', ''];\n      for (const [key, values] of Object.entries(grouped)) {\n        lines.push(`${key}: ${values.join(', ')}`);\n      }\n\n      if (lines.length === 2) {\n        lines.push('לא מולאו תשובות עדיין.');\n      }\n\n      return lines.join('\\n');\n    }\n\n    document.getElementById('copyAnswers').addEventListener('click', async () => {\n      const text = collectAnswers();\n\n      try {\n        await navigator.clipboard.writeText(text);\n        notice.style.display = 'block';\n      } catch (error) {\n        const area = document.createElement('textarea');\n        area.value = text;\n        document.body.appendChild(area);\n        area.select();\n        document.execCommand('copy');\n        area.remove();\n        notice.style.display = 'block';\n      }\n    });\n\n    document.getElementById('downloadAnswers').addEventListener('click', () => {\n      const text = collectAnswers();\n      const blob = new Blob([text], { type: 'text/plain;charset=utf-8' });\n      const url = URL.createObjectURL(blob);\n      const link = document.createElement('a');\n      link.href = url;\n      link.download = 'drive-dog-questionnaire-answers.txt';\n      document.body.appendChild(link);\n      link.click();\n      link.remove();\n      URL.revokeObjectURL(url);\n    });\n  </script>\n</body>\n</html>\n";
const proposalHtml = "<!doctype html>\n<html lang=\"he\" dir=\"rtl\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>הצעת MVP - Drive Dog</title>\n  <style>\n    :root {\n      color-scheme: light;\n      --bg: #f4f6f5;\n      --paper: #ffffff;\n      --ink: #14211c;\n      --muted: #5f6e68;\n      --line: #dce4df;\n      --green: #176b4d;\n      --green-2: #0f4935;\n      --gold: #c18a28;\n      --blue: #24506d;\n      --soft: #eef4f1;\n      --warn: #fff5df;\n    }\n\n    * {\n      box-sizing: border-box;\n    }\n\n    body {\n      margin: 0;\n      font-family: Arial, \"Helvetica Neue\", sans-serif;\n      background: var(--bg);\n      color: var(--ink);\n      line-height: 1.6;\n    }\n\n    .hero {\n      min-height: 74vh;\n      display: flex;\n      align-items: center;\n      padding: 48px 24px 92px;\n      color: #fff;\n      background:\n        linear-gradient(90deg, rgba(15, 73, 53, .96), rgba(23, 107, 77, .84)),\n        url(\"https://images.unsplash.com/photo-1589924691995-400dc9ecc119?auto=format&fit=crop&w=1800&q=80\");\n      background-size: cover;\n      background-position: center;\n    }\n\n    .hero-inner,\n    .wrap {\n      width: min(1080px, calc(100% - 32px));\n      margin: 0 auto;\n    }\n\n    .eyebrow {\n      display: inline-flex;\n      align-items: center;\n      gap: 9px;\n      padding: 8px 12px;\n      border: 1px solid rgba(255, 255, 255, .35);\n      border-radius: 999px;\n      background: rgba(255, 255, 255, .12);\n      font-weight: 700;\n    }\n\n    h1,\n    h2,\n    h3,\n    p {\n      margin-top: 0;\n    }\n\n    h1 {\n      max-width: 780px;\n      margin: 22px 0 16px;\n      font-size: 58px;\n      line-height: 1.08;\n      letter-spacing: 0;\n    }\n\n    .hero p {\n      max-width: 760px;\n      margin-bottom: 0;\n      color: rgba(255, 255, 255, .88);\n      font-size: 22px;\n    }\n\n    .proposal-meta {\n      display: grid;\n      grid-template-columns: repeat(3, minmax(0, 1fr));\n      gap: 10px;\n      max-width: 820px;\n      margin-top: 28px;\n    }\n\n    .meta-item {\n      padding: 12px 14px;\n      border: 1px solid rgba(255, 255, 255, .28);\n      border-radius: 8px;\n      background: rgba(255, 255, 255, .12);\n    }\n\n    .meta-item span {\n      display: block;\n      color: rgba(255, 255, 255, .72);\n      font-size: 13px;\n    }\n\n    .meta-item strong {\n      display: block;\n      margin-top: 3px;\n      color: #fff;\n    }\n\n    .summary-strip {\n      margin-top: -52px;\n      position: relative;\n      z-index: 2;\n    }\n\n    .summary-grid {\n      display: grid;\n      grid-template-columns: repeat(4, minmax(0, 1fr));\n      gap: 12px;\n    }\n\n    .summary-item,\n    .panel,\n    .scope-item,\n    .phase,\n    .risk {\n      background: var(--paper);\n      border: 1px solid var(--line);\n      border-radius: 8px;\n      box-shadow: 0 16px 42px rgba(34, 48, 42, .07);\n    }\n\n    .summary-item {\n      min-height: 118px;\n      padding: 18px;\n    }\n\n    .summary-item strong {\n      display: block;\n      margin-bottom: 8px;\n      color: var(--green-2);\n      font-size: 26px;\n      line-height: 1.2;\n    }\n\n    .summary-item span,\n    p,\n    li {\n      color: var(--muted);\n    }\n\n    section {\n      padding: 58px 0;\n    }\n\n    .section-head {\n      margin-bottom: 20px;\n    }\n\n    .section-head span {\n      color: var(--gold);\n      font-weight: 800;\n    }\n\n    h2 {\n      margin-bottom: 8px;\n      font-size: 34px;\n      line-height: 1.2;\n      letter-spacing: 0;\n    }\n\n    h3 {\n      margin-bottom: 10px;\n      font-size: 21px;\n      line-height: 1.25;\n    }\n\n    .grid-2,\n    .grid-3 {\n      display: grid;\n      gap: 14px;\n    }\n\n    .grid-2 {\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n    }\n\n    .grid-3 {\n      grid-template-columns: repeat(3, minmax(0, 1fr));\n    }\n\n    .panel,\n    .scope-item,\n    .phase,\n    .risk {\n      padding: 20px;\n    }\n\n    .panel.accent {\n      background: var(--soft);\n      border-color: #c9d9d1;\n    }\n\n    ul,\n    ol {\n      margin: 0;\n      padding: 0 20px 0 0;\n    }\n\n    li {\n      margin: 8px 0;\n    }\n\n    .tag {\n      display: inline-flex;\n      margin: 0 0 12px;\n      padding: 5px 9px;\n      border-radius: 999px;\n      background: #e7f0eb;\n      color: var(--green-2);\n      font-size: 13px;\n      font-weight: 700;\n    }\n\n    .scope-list {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: 12px;\n    }\n\n    .scope-item {\n      min-height: 132px;\n    }\n\n    .scope-item strong {\n      display: block;\n      margin-bottom: 7px;\n      font-size: 18px;\n    }\n\n    .timeline {\n      display: grid;\n      gap: 12px;\n      counter-reset: phase;\n    }\n\n    .phase {\n      display: grid;\n      grid-template-columns: 58px 1fr;\n      gap: 14px;\n      align-items: start;\n    }\n\n    .phase::before {\n      counter-increment: phase;\n      content: counter(phase);\n      display: grid;\n      place-items: center;\n      width: 42px;\n      height: 42px;\n      border-radius: 999px;\n      background: var(--green);\n      color: #fff;\n      font-weight: 800;\n    }\n\n    .risk {\n      background: var(--warn);\n      border-color: #ecd7a7;\n    }\n\n    .placeholder {\n      display: grid;\n      gap: 10px;\n    }\n\n    .placeholder-row {\n      display: grid;\n      grid-template-columns: 180px 1fr;\n      gap: 12px;\n      align-items: center;\n      padding: 12px 0;\n      border-bottom: 1px solid var(--line);\n    }\n\n    .placeholder-row:last-child {\n      border-bottom: 0;\n    }\n\n    .placeholder-row strong {\n      color: var(--green-2);\n    }\n\n    .blank {\n      min-height: 36px;\n      border: 1px dashed #b9c6bf;\n      border-radius: 7px;\n      background: #fafcfb;\n    }\n\n    .signature-grid {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: 14px;\n    }\n\n    label {\n      display: block;\n      margin-bottom: 6px;\n      color: var(--green-2);\n      font-weight: 700;\n    }\n\n    input,\n    textarea {\n      width: 100%;\n      border: 1px solid #cbd8d1;\n      border-radius: 7px;\n      padding: 11px 12px;\n      font: inherit;\n      background: #fff;\n      color: var(--ink);\n    }\n\n    textarea {\n      min-height: 84px;\n      resize: vertical;\n    }\n\n    .field {\n      margin-bottom: 14px;\n    }\n\n    .signature-pad {\n      width: 100%;\n      height: 170px;\n      border: 1px dashed #9fb4aa;\n      border-radius: 8px;\n      background: #fff;\n      touch-action: none;\n    }\n\n    .checkbox-row {\n      display: flex;\n      align-items: flex-start;\n      gap: 9px;\n      margin: 12px 0 16px;\n      color: var(--muted);\n    }\n\n    .checkbox-row input {\n      width: auto;\n      margin-top: 5px;\n    }\n\n    .buttons {\n      display: flex;\n      flex-wrap: wrap;\n      gap: 10px;\n    }\n\n    button {\n      border: 0;\n      border-radius: 7px;\n      padding: 11px 15px;\n      font: inherit;\n      font-weight: 700;\n      cursor: pointer;\n    }\n\n    .primary {\n      background: var(--green);\n      color: #fff;\n    }\n\n    .secondary {\n      background: #e4ece8;\n      color: var(--ink);\n    }\n\n    .notice {\n      display: none;\n      margin-top: 12px;\n      color: var(--green-2);\n      font-weight: 700;\n    }\n\n    .footer {\n      padding: 34px 0 46px;\n      color: var(--muted);\n      font-size: 14px;\n      text-align: center;\n    }\n\n    @media print {\n      body {\n        background: #fff;\n      }\n\n      .hero {\n        min-height: auto;\n        padding: 36px 24px;\n      }\n\n      .summary-strip {\n        margin-top: 0;\n      }\n\n      .summary-item,\n      .panel,\n      .scope-item,\n      .phase,\n      .risk {\n        box-shadow: none;\n      }\n    }\n\n    @media (max-width: 820px) {\n      .hero {\n        min-height: 66vh;\n        padding: 36px 18px 78px;\n      }\n\n      .hero-inner,\n      .wrap {\n        width: min(100% - 24px, 1080px);\n      }\n\n      h1 {\n        font-size: 40px;\n      }\n\n      .hero p {\n        font-size: 18px;\n      }\n\n      .summary-grid,\n      .grid-2,\n      .grid-3,\n      .scope-list,\n      .proposal-meta,\n      .signature-grid {\n        grid-template-columns: 1fr;\n      }\n\n      .placeholder-row {\n        grid-template-columns: 1fr;\n      }\n    }\n  </style>\n</head>\n<body>\n  <header class=\"hero\">\n    <div class=\"hero-inner\">\n      <div class=\"eyebrow\">הצעת MVP | דרייב דוג</div>\n      <h1>מערכת CRM והזמנות ללקוחות חוזרים</h1>\n      <p>מסמך הצגת MVP למערכת שתאגד לקוחות, קטלוג מוצרים, מחירים אישיים, הזמנות, תשלומים, חשבוניות ומשלוחים במקום אחד.</p>\n      <div class=\"proposal-meta\">\n        <div class=\"meta-item\"><span>לכבוד</span><strong>דרייב דוג</strong></div>\n        <div class=\"meta-item\"><span>מגיש ההצעה</span><strong>Orma AI</strong></div>\n        <div class=\"meta-item\"><span>קישור</span><strong>proposals.orma-ai.com</strong></div>\n      </div>\n    </div>\n  </header>\n\n  <main>\n    <div class=\"summary-strip\">\n      <div class=\"wrap summary-grid\">\n        <div class=\"summary-item\">\n          <strong>~100</strong>\n          <span>לקוחות קיימים בתחילת הדרך</span>\n        </div>\n        <div class=\"summary-item\">\n          <strong>5-10</strong>\n          <span>הזמנות בתקופת פעילות טיפוסית</span>\n        </div>\n        <div class=\"summary-item\">\n          <strong>30-40</strong>\n          <span>מוצרים בקטלוג הראשוני</span>\n        </div>\n        <div class=\"summary-item\">\n          <strong>2 ימים</strong>\n          <span>התראה מינימלית לפני אספקה</span>\n        </div>\n      </div>\n    </div>\n\n    <section>\n      <div class=\"wrap grid-2\">\n        <article class=\"panel accent\">\n          <span class=\"tag\">מטרת הפרויקט</span>\n          <h2>לעשות סדר בתהליך המכירה והאספקה</h2>\n          <p>המערכת נועדה להחליף עבודה מפוזרת בוואטסאפ ובטלפון במרכז ניהולי אחד, שבו בעל העסק רואה לקוחות, הזמנות, תשלומים, חשבוניות ומשלוחים בצורה מהירה וברורה.</p>\n        </article>\n        <article class=\"panel\">\n          <span class=\"tag\">קהל יעד</span>\n          <h2>לקוחות קיימים, לא חנות פתוחה לציבור</h2>\n          <p>הלקוח לא נרשם לבד. בעל העסק מכניס אותו למערכת, ולאחר מכן הלקוח יכול להיכנס עם מספר טלפון וסיסמה כדי לבצע הזמנה חוזרת או לבחור מוצרים מהקטלוג. בכניסה הראשונה הלקוח מחליף את הסיסמה הראשונית.</p>\n        </article>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap\">\n        <div class=\"section-head\">\n          <span>01</span>\n          <h2>מה כלול ב-MVP</h2>\n          <p>גרסה ראשונה ממוקדת שמאפשרת שימוש אמיתי בעסק בלי לבנות מערכת כבדה מדי.</p>\n        </div>\n        <div class=\"scope-list\">\n          <div class=\"scope-item\"><strong>ניהול לקוחות</strong><span>שם, טלפון, כתובת, אזור, הערות, היסטוריית הזמנות ומחירים אישיים.</span></div>\n          <div class=\"scope-item\"><strong>קטלוג מוצרים</strong><span>מותג, סדרה, סוג, טעם, משקל, מחיר בסיס ותמונה.</span></div>\n          <div class=\"scope-item\"><strong>מחירים והנחות</strong><span>מחיר קבוע ללקוח, הנחות ומבצעים פשוטים.</span></div>\n          <div class=\"scope-item\"><strong>פורטל לקוח</strong><span>כניסה עם טלפון וסיסמה, החלפת סיסמה ראשונית, צפייה בקטלוג והזמנה עצמאית.</span></div>\n          <div class=\"scope-item\"><strong>הזמנה חוזרת</strong><span>אפשרות מהירה להזמין שוב את המוצר האחרון שנרכש.</span></div>\n          <div class=\"scope-item\"><strong>עגלה והזמנה</strong><span>תמיכה בכמה מוצרים באותה הזמנה, כתובת, הערות ומועד אספקה.</span></div>\n          <div class=\"scope-item\"><strong>הזמנה ידנית</strong><span>בעל העסק יכול לפתוח הזמנה עבור לקוחות מבוגרים או הזמנות טלפוניות.</span></div>\n          <div class=\"scope-item\"><strong>תשלומים וחשבוניות</strong><span>קישור תשלום דרך משולם/Grow, קליטת סטטוס תשלום וחשבונית אונליין.</span></div>\n          <div class=\"scope-item\"><strong>מזומן לשליח</strong><span>אפשרות חריגה לתשלום מזומן, עם סימון ידני של סטטוס תשלום.</span></div>\n          <div class=\"scope-item\"><strong>מסך משלוחים</strong><span>רשימת הזמנות לפי תאריך, אזור וסטטוס תשלום.</span></div>\n        </div>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap grid-2\">\n        <article class=\"panel\">\n          <div class=\"section-head\">\n            <span>02</span>\n            <h2>זרימת לקוח</h2>\n          </div>\n          <ol>\n            <li>נכנס לעמוד ההזמנות.</li>\n            <li>מזין טלפון וסיסמה.</li>\n            <li>בכניסה ראשונה מחליף את הסיסמה הראשונית.</li>\n            <li>רואה קטלוג ומוצר אחרון שנרכש.</li>\n            <li>בוחר מוצרים וכמויות.</li>\n            <li>מאשר כתובת ומוסיף הערות.</li>\n            <li>בוחר תשלום אונליין או מזומן לשליח.</li>\n            <li>הזמנה נכנסת למערכת לניהול בעל העסק.</li>\n          </ol>\n        </article>\n        <article class=\"panel\">\n          <div class=\"section-head\">\n            <span>03</span>\n            <h2>זרימת בעל העסק</h2>\n          </div>\n          <ol>\n            <li>מוסיף לקוחות ומוצרים.</li>\n            <li>מגדיר מחירים אישיים והנחות.</li>\n            <li>פותח הזמנה ידנית כשצריך.</li>\n            <li>יוצר קישור תשלום ושולח ללקוח.</li>\n            <li>רואה תשלומים וחשבוניות.</li>\n            <li>מנהל משלוחים לפי אזור ותאריך.</li>\n          </ol>\n        </article>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap grid-2\">\n        <article class=\"panel accent\">\n          <div class=\"section-head\">\n            <span>04</span>\n            <h2>אינטגרציית משולם / Grow</h2>\n          </div>\n          <ul>\n            <li>יצירת קישור תשלום להזמנה.</li>\n            <li>העברת הלקוח לעמוד תשלום של Grow.</li>\n            <li>קליטת סטטוס תשלום דרך callback / webhook.</li>\n            <li>שמירת מספר חשבונית וקישור חשבונית כאשר Grow מחזירה אותם.</li>\n            <li>אין שמירת פרטי אשראי במערכת.</li>\n          </ul>\n        </article>\n        <article class=\"risk\">\n          <div class=\"section-head\">\n            <span>סיכון פתוח</span>\n            <h2>חשבונית על מזומן לשליח</h2>\n          </div>\n          <p>תשלום אונליין דרך Grow מתאים ל-MVP. לגבי תשלום מזומן לשליח, צריך אישור טכני מ-Grow האם ניתן להפיק חשבונית מס/קבלה דרך API עבור עסקה שלא שולמה אונליין.</p>\n        </article>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap\">\n        <div class=\"section-head\">\n          <span>05</span>\n          <h2>תהליך עבודה מוצע</h2>\n        </div>\n        <div class=\"timeline\">\n          <div class=\"phase\">\n            <div>\n              <h3>אפיון סופי ומפת מסכים</h3>\n              <p>סגירת זרימות, סטטוסים, מסכים והתנהגות מרכזית לפני פיתוח.</p>\n            </div>\n          </div>\n          <div class=\"phase\">\n            <div>\n              <h3>עיצוב ופיתוח בסיס ניהולי</h3>\n              <p>לקוחות, מוצרים, מחירים, הזמנות ידניות ודשבורד ניהולי.</p>\n            </div>\n          </div>\n          <div class=\"phase\">\n            <div>\n              <h3>פורטל לקוח</h3>\n              <p>כניסה עם קוד, קטלוג, עגלה, כתובת, הערות והזמנה חוזרת.</p>\n            </div>\n          </div>\n          <div class=\"phase\">\n            <div>\n              <h3>חיבור משולם / Grow</h3>\n              <p>קישור תשלום, webhook, סטטוס תשלום וחשבונית אונליין.</p>\n            </div>\n          </div>\n          <div class=\"phase\">\n            <div>\n              <h3>בדיקות ועלייה לשימוש</h3>\n              <p>בדיקות מובייל, תרחישי תשלום, הזמנות ידניות, משלוחים ותיקונים אחרונים.</p>\n            </div>\n          </div>\n        </div>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap grid-2\">\n        <article class=\"panel\">\n          <div class=\"section-head\">\n            <span>06</span>\n            <h2>הנחות עבודה</h2>\n          </div>\n          <ul>\n            <li>בעל העסק מזין לקוחות למערכת.</li>\n            <li>הלקוחות לא נרשמים לבד.</li>\n            <li>התשלום הרצוי הוא בזמן ההזמנה.</li>\n            <li>מזומן לשליח הוא חריג, לא ברירת מחדל.</li>\n            <li>המערכת צריכה לעבוד טוב גם במובייל וגם במחשב.</li>\n            <li>משלוחים מנוהלים ידנית לפי תאריך ואזור.</li>\n            <li>תחזוקה חודשית לאחר העלייה לאוויר: 300 ₪ + מע״מ לחודש.</li>\n          </ul>\n        </article>\n      </div>\n    </section>\n\n    <section>\n      <div class=\"wrap\">\n        <div class=\"section-head\">\n          <span>07</span>\n          <h2>אישור וחתימה דיגיטלית</h2>\n          <p>לאישור ההצעה, ניתן למלא פרטים ולחתום בתיבה. בלחיצה על אישור נוצר קובץ אישור חתום ונפתח מייל מוכן לשליחה ל-Orma AI.</p>\n        </div>\n        <div class=\"panel\">\n          <div class=\"signature-grid\">\n            <div>\n              <div class=\"field\">\n                <label for=\"signName\">שם מלא</label>\n                <input id=\"signName\" autocomplete=\"name\">\n              </div>\n              <div class=\"field\">\n                <label for=\"signPhone\">טלפון</label>\n                <input id=\"signPhone\" autocomplete=\"tel\">\n              </div>\n              <div class=\"field\">\n                <label for=\"signEmail\">אימייל</label>\n                <input id=\"signEmail\" autocomplete=\"email\">\n              </div>\n              <div class=\"field\">\n                <label for=\"signNotes\">הערות</label>\n                <textarea id=\"signNotes\"></textarea>\n              </div>\n            </div>\n            <div>\n              <label for=\"signaturePad\">חתימה</label>\n              <canvas id=\"signaturePad\" class=\"signature-pad\"></canvas>\n              <label class=\"checkbox-row\">\n                <input id=\"signApproval\" type=\"checkbox\">\n                <span>אני מאשר את ההצעה, תכולת ה-MVP, תנאי העבודה והעלות החודשית של 300 ₪ + מע״מ כמפורט במסמך זה.</span>\n              </label>\n              <div class=\"buttons\">\n                <button class=\"primary\" type=\"button\" id=\"downloadApproval\">אישור ושליחת חתימה</button>\n                <button class=\"secondary\" type=\"button\" id=\"clearSignature\">ניקוי חתימה</button>\n                <button class=\"secondary\" type=\"button\" id=\"printProposal\">הדפסה / PDF</button>\n              </div>\n              <div class=\"notice\" id=\"signatureNotice\">נוצר קובץ אישור חתום ונפתח מייל ל־Ami@hai.tech. יש לצרף את הקובץ למייל ולשלוח.</div>\n            </div>\n          </div>\n        </div>\n      </div>\n    </section>\n  </main>\n\n  <footer class=\"footer\">\n    Orma AI | פתרונות AI, אוטומציה ומערכות ניהול | proposals.orma-ai.com\n  </footer>\n  <script>\n    const canvas = document.getElementById('signaturePad');\n    const ctx = canvas.getContext('2d');\n    let drawing = false;\n\n    function resizeCanvas() {\n      const rect = canvas.getBoundingClientRect();\n      const image = canvas.toDataURL();\n      canvas.width = Math.max(1, Math.floor(rect.width * window.devicePixelRatio));\n      canvas.height = Math.max(1, Math.floor(rect.height * window.devicePixelRatio));\n      ctx.setTransform(window.devicePixelRatio, 0, 0, window.devicePixelRatio, 0, 0);\n      ctx.lineWidth = 2.3;\n      ctx.lineCap = 'round';\n      ctx.strokeStyle = '#14211c';\n      if (image) {\n        const img = new Image();\n        img.onload = () => ctx.drawImage(img, 0, 0, rect.width, rect.height);\n        img.src = image;\n      }\n    }\n\n    function point(event) {\n      const rect = canvas.getBoundingClientRect();\n      const touch = event.touches ? event.touches[0] : event;\n      return {\n        x: touch.clientX - rect.left,\n        y: touch.clientY - rect.top\n      };\n    }\n\n    function start(event) {\n      drawing = true;\n      const p = point(event);\n      ctx.beginPath();\n      ctx.moveTo(p.x, p.y);\n      event.preventDefault();\n    }\n\n    function draw(event) {\n      if (!drawing) return;\n      const p = point(event);\n      ctx.lineTo(p.x, p.y);\n      ctx.stroke();\n      event.preventDefault();\n    }\n\n    function stop() {\n      drawing = false;\n    }\n\n    function fieldValue(id) {\n      return document.getElementById(id).value.trim();\n    }\n\n    function signatureIsBlank() {\n      const pixels = ctx.getImageData(0, 0, canvas.width, canvas.height).data;\n      for (let i = 3; i < pixels.length; i += 4) {\n        if (pixels[i] !== 0) return false;\n      }\n      return true;\n    }\n\n    function downloadSignedApproval() {\n      const approved = document.getElementById('signApproval').checked;\n      const name = fieldValue('signName');\n      if (!approved || !name || signatureIsBlank()) {\n        alert('צריך למלא שם, לסמן אישור ולחתום לפני שליחה.');\n        return;\n      }\n\n      const signature = canvas.toDataURL('image/png');\n      const date = new Date().toLocaleString('he-IL');\n      const html = `<!doctype html><html lang=\"he\" dir=\"rtl\"><meta charset=\"utf-8\"><title>אישור הצעת MVP - דרייב דוג</title><body style=\"font-family:Arial,sans-serif;line-height:1.6;padding:32px;max-width:760px;margin:auto\"><h1>אישור הצעת MVP - דרייב דוג</h1><p><strong>תאריך אישור:</strong> ${date}</p><p><strong>שם מלא:</strong> ${fieldValue('signName')}</p><p><strong>טלפון:</strong> ${fieldValue('signPhone')}</p><p><strong>אימייל:</strong> ${fieldValue('signEmail')}</p><p><strong>הערות:</strong><br>${fieldValue('signNotes').replaceAll('\\n', '<br>')}</p><p>אני מאשר את ההצעה, תכולת ה-MVP, תנאי העבודה והעלות החודשית של 300 ₪ + מע״מ כמפורט במסמך.</p><h2>חתימה</h2><img src=\"${signature}\" style=\"border:1px solid #ccc;max-width:420px;width:100%\"><footer style=\"margin-top:32px;color:#667\">Orma AI | proposals.orma-ai.com</footer></body></html>`;\n      const blob = new Blob([html], { type: 'text/html;charset=utf-8' });\n      const url = URL.createObjectURL(blob);\n      const link = document.createElement('a');\n      link.href = url;\n      link.download = 'drive-dog-mvp-signed-approval.html';\n      document.body.appendChild(link);\n      link.click();\n      link.remove();\n      URL.revokeObjectURL(url);\n      document.getElementById('signatureNotice').style.display = 'block';\n\n      const subject = encodeURIComponent('אישור הצעת MVP - דרייב דוג');\n      const body = encodeURIComponent([\n        'שלום,',\n        '',\n        'מצורף אישור חתום להצעת MVP - דרייב דוג.',\n        '',\n        `שם: ${fieldValue('signName')}`,\n        `טלפון: ${fieldValue('signPhone')}`,\n        `אימייל: ${fieldValue('signEmail')}`,\n        `תאריך אישור: ${date}`,\n        '',\n        'הערות:',\n        fieldValue('signNotes') || '-',\n        '',\n        'יש לצרף למייל את קובץ האישור החתום שירד למחשב/טלפון.'\n      ].join('\\n'));\n      window.location.href = `mailto:Ami@hai.tech?subject=${subject}&body=${body}`;\n    }\n\n    window.addEventListener('resize', resizeCanvas);\n    resizeCanvas();\n    canvas.addEventListener('mousedown', start);\n    canvas.addEventListener('mousemove', draw);\n    window.addEventListener('mouseup', stop);\n    canvas.addEventListener('touchstart', start, { passive: false });\n    canvas.addEventListener('touchmove', draw, { passive: false });\n    window.addEventListener('touchend', stop);\n    document.getElementById('clearSignature').addEventListener('click', () => {\n      ctx.clearRect(0, 0, canvas.width, canvas.height);\n    });\n    document.getElementById('printProposal').addEventListener('click', () => window.print());\n    document.getElementById('downloadApproval').addEventListener('click', downloadSignedApproval);\n  </script>\n</body>\n</html>\n";
const adminHtml = "<!doctype html>\n<html lang=\"he\" dir=\"rtl\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>Drive Dog | ניהול</title>\n  <style>\n    :root {\n      color-scheme: light;\n      --bg: #f4f6f5;\n      --panel: #ffffff;\n      --panel-2: #f9faf9;\n      --ink: #17211d;\n      --muted: #66736d;\n      --line: #dce3df;\n      --brand: #27745c;\n      --brand-dark: #1f5f4b;\n      --warn: #a15c09;\n      --danger: #b42318;\n      --ok: #197a45;\n      --shadow: 0 12px 30px rgba(33, 43, 38, 0.08);\n    }\n\n    * { box-sizing: border-box; }\n\n    body {\n      margin: 0;\n      font-family: Arial, \"Helvetica Neue\", sans-serif;\n      background: var(--bg);\n      color: var(--ink);\n      line-height: 1.45;\n    }\n\n    button,\n    input,\n    select,\n    textarea {\n      font: inherit;\n    }\n\n    button {\n      border: 0;\n      cursor: pointer;\n    }\n\n    .app {\n      min-height: 100vh;\n      display: grid;\n      grid-template-columns: 250px 1fr;\n    }\n\n    .sidebar {\n      position: sticky;\n      top: 0;\n      height: 100vh;\n      padding: 18px;\n      background: #17211d;\n      color: #ffffff;\n      display: flex;\n      flex-direction: column;\n      gap: 18px;\n    }\n\n    .brand {\n      display: flex;\n      align-items: center;\n      gap: 10px;\n      min-height: 44px;\n      font-weight: 800;\n      font-size: 18px;\n    }\n\n    .mark {\n      width: 36px;\n      height: 36px;\n      border-radius: 8px;\n      display: grid;\n      place-items: center;\n      background: #d9f2e8;\n      color: #17211d;\n      font-weight: 900;\n    }\n\n    nav {\n      display: grid;\n      gap: 8px;\n    }\n\n    .nav-button {\n      min-height: 42px;\n      padding: 10px 12px;\n      border-radius: 7px;\n      text-align: right;\n      color: rgba(255, 255, 255, 0.78);\n      background: transparent;\n    }\n\n    .nav-button.active,\n    .nav-button:hover {\n      color: #ffffff;\n      background: rgba(255, 255, 255, 0.12);\n    }\n\n    .side-note {\n      margin-top: auto;\n      padding: 12px;\n      border: 1px solid rgba(255, 255, 255, 0.16);\n      border-radius: 8px;\n      color: rgba(255, 255, 255, 0.72);\n      font-size: 13px;\n    }\n\n    main {\n      padding: 22px;\n      min-width: 0;\n    }\n\n    .topbar {\n      display: flex;\n      align-items: flex-start;\n      justify-content: space-between;\n      gap: 16px;\n      margin-bottom: 18px;\n    }\n\n    h1 {\n      margin: 0 0 5px;\n      font-size: 25px;\n      letter-spacing: 0;\n    }\n\n    .subtitle {\n      margin: 0;\n      color: var(--muted);\n      font-size: 14px;\n    }\n\n    .toolbar {\n      display: flex;\n      flex-wrap: wrap;\n      gap: 8px;\n      justify-content: flex-end;\n    }\n\n    .button {\n      min-height: 38px;\n      padding: 9px 12px;\n      border-radius: 7px;\n      background: #e5ece8;\n      color: var(--ink);\n      font-weight: 700;\n      white-space: nowrap;\n    }\n\n    .button.primary {\n      background: var(--brand);\n      color: #ffffff;\n    }\n\n    .button.primary:hover { background: var(--brand-dark); }\n    .button.danger { color: #ffffff; background: var(--danger); }\n    .button.ghost { background: transparent; border: 1px solid var(--line); }\n\n    .grid {\n      display: grid;\n      gap: 14px;\n    }\n\n    .metrics {\n      grid-template-columns: repeat(4, minmax(0, 1fr));\n      margin-bottom: 14px;\n    }\n\n    .metric,\n    .panel {\n      background: var(--panel);\n      border: 1px solid var(--line);\n      border-radius: 8px;\n      box-shadow: var(--shadow);\n    }\n\n    .metric {\n      padding: 15px;\n      min-height: 96px;\n    }\n\n    .metric span {\n      color: var(--muted);\n      font-size: 13px;\n    }\n\n    .metric strong {\n      display: block;\n      margin-top: 8px;\n      font-size: 28px;\n    }\n\n    .panel {\n      padding: 16px;\n      overflow: hidden;\n    }\n\n    .panel-head {\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      gap: 10px;\n      margin-bottom: 12px;\n    }\n\n    h2 {\n      margin: 0;\n      font-size: 18px;\n      letter-spacing: 0;\n    }\n\n    .split {\n      display: grid;\n      grid-template-columns: minmax(0, 1.25fr) minmax(320px, 0.75fr);\n      gap: 14px;\n      align-items: start;\n    }\n\n    .form-grid {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: 10px;\n    }\n\n    .field.full { grid-column: 1 / -1; }\n\n    label {\n      display: block;\n      margin-bottom: 5px;\n      color: var(--muted);\n      font-size: 12px;\n      font-weight: 700;\n    }\n\n    input,\n    select,\n    textarea {\n      width: 100%;\n      border: 1px solid #ccd7d1;\n      border-radius: 7px;\n      padding: 9px 10px;\n      background: #ffffff;\n      color: var(--ink);\n    }\n\n    textarea {\n      min-height: 76px;\n      resize: vertical;\n    }\n\n    table {\n      width: 100%;\n      border-collapse: collapse;\n      min-width: 760px;\n    }\n\n    th,\n    td {\n      padding: 10px 8px;\n      border-bottom: 1px solid var(--line);\n      text-align: right;\n      vertical-align: top;\n      font-size: 14px;\n    }\n\n    th {\n      color: var(--muted);\n      font-size: 12px;\n      background: var(--panel-2);\n      position: sticky;\n      top: 0;\n      z-index: 1;\n    }\n\n    .table-wrap {\n      overflow-x: auto;\n      border: 1px solid var(--line);\n      border-radius: 8px;\n    }\n\n    .row-actions {\n      display: flex;\n      gap: 6px;\n      flex-wrap: wrap;\n    }\n\n    .mini {\n      min-height: 30px;\n      padding: 6px 9px;\n      border-radius: 6px;\n      background: #edf2ef;\n      color: var(--ink);\n      font-weight: 700;\n      font-size: 12px;\n    }\n\n    .status {\n      display: inline-flex;\n      align-items: center;\n      min-height: 26px;\n      padding: 4px 8px;\n      border-radius: 999px;\n      background: #edf2ef;\n      color: var(--muted);\n      font-size: 12px;\n      font-weight: 700;\n      white-space: nowrap;\n    }\n\n    .status.ok { background: #e3f4ea; color: var(--ok); }\n    .status.warn { background: #fff3df; color: var(--warn); }\n    .status.danger { background: #fde8e6; color: var(--danger); }\n\n    .filters {\n      display: grid;\n      grid-template-columns: repeat(4, minmax(0, 1fr));\n      gap: 10px;\n      margin-bottom: 12px;\n    }\n\n    .order-builder {\n      display: grid;\n      gap: 10px;\n    }\n\n    .item-row {\n      display: grid;\n      grid-template-columns: minmax(0, 1fr) 82px 42px;\n      gap: 8px;\n      align-items: end;\n    }\n\n    .total-line {\n      display: flex;\n      justify-content: space-between;\n      gap: 12px;\n      padding-top: 8px;\n      border-top: 1px solid var(--line);\n      font-weight: 800;\n      font-size: 18px;\n    }\n\n    .list {\n      display: grid;\n      gap: 10px;\n    }\n\n    .delivery-card {\n      padding: 12px;\n      border: 1px solid var(--line);\n      border-radius: 8px;\n      background: #ffffff;\n    }\n\n    .delivery-card.cash {\n      border-color: #efc06b;\n      background: #fffaf0;\n    }\n\n    .muted { color: var(--muted); }\n    .nowrap { white-space: nowrap; }\n    .hidden { display: none !important; }\n\n    .empty {\n      padding: 22px;\n      text-align: center;\n      color: var(--muted);\n      background: var(--panel-2);\n      border: 1px dashed var(--line);\n      border-radius: 8px;\n    }\n\n    .toast {\n      position: fixed;\n      left: 18px;\n      bottom: 18px;\n      max-width: min(420px, calc(100% - 36px));\n      padding: 12px 14px;\n      border-radius: 8px;\n      background: #17211d;\n      color: #ffffff;\n      box-shadow: var(--shadow);\n      z-index: 10;\n    }\n\n    @media (max-width: 960px) {\n      .app { grid-template-columns: 1fr; }\n      .sidebar {\n        position: static;\n        height: auto;\n      }\n      nav {\n        grid-template-columns: repeat(3, minmax(0, 1fr));\n      }\n      .side-note { display: none; }\n      .split,\n      .metrics,\n      .filters {\n        grid-template-columns: 1fr;\n      }\n      .topbar {\n        display: grid;\n      }\n      .toolbar {\n        justify-content: stretch;\n      }\n      .toolbar .button {\n        flex: 1;\n      }\n    }\n\n    @media (max-width: 620px) {\n      main { padding: 14px; }\n      nav { grid-template-columns: repeat(2, minmax(0, 1fr)); }\n      .form-grid,\n      .item-row {\n        grid-template-columns: 1fr;\n      }\n      .item-row .mini {\n        min-height: 36px;\n      }\n    }\n  </style>\n</head>\n<body>\n  <div class=\"app\">\n    <aside class=\"sidebar\">\n      <div class=\"brand\"><span class=\"mark\">DD</span><span>Drive Dog</span></div>\n      <nav id=\"nav\"></nav>\n      <div class=\"side-note\">MVP פנימי: הדאטה נשמר בדפדפן בלבד. Grow / משולם מסומן כ-stub ולא מחייב בפועל.</div>\n    </aside>\n    <main>\n      <div class=\"topbar\">\n        <div>\n          <h1 id=\"pageTitle\">דשבורד</h1>\n          <p id=\"pageSubtitle\" class=\"subtitle\">תמונת מצב קצרה על לקוחות, הזמנות ותשלומים.</p>\n        </div>\n        <div class=\"toolbar\">\n          <button class=\"button ghost\" id=\"exportBtn\" type=\"button\">ייצוא JSON</button>\n          <button class=\"button ghost\" id=\"resetBtn\" type=\"button\">איפוס דמו</button>\n        </div>\n      </div>\n      <section id=\"view\"></section>\n    </main>\n  </div>\n  <div class=\"toast hidden\" id=\"toast\"></div>\n\n  <script>\n    const STORAGE_KEY = 'driveDogAdminMvpV1';\n    const tabs = [\n      ['dashboard', 'דשבורד', 'תמונת מצב קצרה על לקוחות, הזמנות ותשלומים.'],\n      ['customers', 'לקוחות', 'ניהול לקוחות קיימים בלבד. אין הרשמה פתוחה.'],\n      ['products', 'מוצרים', 'קטלוג בסיסי של משפחות ווריאנטים.'],\n      ['pricing', 'מחירים', 'מחיר אישי או הנחה לפי לקוח ומוצר.'],\n      ['orders', 'הזמנות', 'יצירת הזמנה ידנית וניהול סטטוס תשלום.'],\n      ['deliveries', 'משלוחים', 'רשימת אספקות לפי תאריך ואזור.'],\n      ['settings', 'הגדרות', 'תלויות חיצוניות שמסומנות כ-stub.']\n    ];\n\n    const seed = {\n      customers: [\n        { id: 'c1', name: 'עמי כהן', phone: '050-1111111', address: 'הכלנית 12', city: 'ראשון לציון', area: 'מרכז', deliveryNotes: 'להתקשר לפני הגעה', internalNotes: 'מעדיף שק 12 ק\"ג', active: true },\n        { id: 'c2', name: 'דנה לוי', phone: '052-2222222', address: 'הגפן 8', city: 'רחובות', area: 'שפלה', deliveryNotes: 'להשאיר ליד הדלת', internalNotes: 'משלמת אונליין', active: true },\n        { id: 'c3', name: 'יוסי מזרחי', phone: '054-3333333', address: 'העצמאות 40', city: 'אשדוד', area: 'דרום', deliveryNotes: 'כלב גדול בחצר', internalNotes: 'מזומן לשליח', active: true }\n      ],\n      products: [\n        { id: 'p1', brand: 'Brit', series: 'Care', animal: 'כלב', stage: 'בוגר', flavor: 'כבש ואורז', weightKg: 12, name: 'Brit Care כבש ואורז 12 ק\"ג', basePrice: 279, active: true },\n        { id: 'p2', brand: 'Monge', series: 'Natural', animal: 'כלב', stage: 'גור', flavor: 'עוף', weightKg: 12, name: 'Monge גור עוף 12 ק\"ג', basePrice: 295, active: true },\n        { id: 'p3', brand: 'Acana', series: 'Classic', animal: 'כלב', stage: 'בוגר', flavor: 'עוף', weightKg: 11.4, name: 'Acana Classic עוף 11.4 ק\"ג', basePrice: 349, active: true },\n        { id: 'p4', brand: 'Royal Canin', series: 'Indoor', animal: 'חתול', stage: 'בוגר', flavor: 'עוף', weightKg: 4, name: 'Royal Canin Indoor חתול 4 ק\"ג', basePrice: 189, active: true },\n        { id: 'p5', brand: 'Josera', series: 'SensiCat', animal: 'חתול', stage: 'בוגר', flavor: 'עוף', weightKg: 10, name: 'Josera SensiCat 10 ק\"ג', basePrice: 265, active: true }\n      ],\n      prices: [\n        { id: 'cp1', customerId: 'c1', productId: 'p1', customPrice: 259, discountPercent: 0, notes: 'מחיר קבוע' },\n        { id: 'cp2', customerId: 'c2', productId: 'p4', customPrice: 0, discountPercent: 8, notes: 'הנחת לקוחה קבועה' }\n      ],\n      orders: [\n        { id: 'o1001', customerId: 'c1', createdAt: '2026-07-22', deliveryDate: '2026-07-25', status: 'new', paymentStatus: 'pending_online_payment', source: 'manual', paymentUrl: 'https://pay.example.test/orders/o1001', notes: 'לשלוח קישור תשלום', items: [{ productId: 'p1', quantity: 1, unitPrice: 259 }] },\n        { id: 'o1002', customerId: 'c2', createdAt: '2026-07-21', deliveryDate: '2026-07-24', status: 'confirmed', paymentStatus: 'paid_online', source: 'manual', paymentUrl: 'https://pay.example.test/orders/o1002', notes: '', items: [{ productId: 'p4', quantity: 2, unitPrice: 174 }] },\n        { id: 'o1003', customerId: 'c3', createdAt: '2026-07-20', deliveryDate: '2026-07-26', status: 'confirmed', paymentStatus: 'cash_on_delivery', source: 'manual', paymentUrl: '', notes: 'מזומן לשליח', items: [{ productId: 'p3', quantity: 1, unitPrice: 349 }] }\n      ],\n      selected: { customerId: 'c1', productId: 'p1' }\n    };\n\n    let state = loadState();\n    let currentTab = 'dashboard';\n\n    function clone(value) {\n      return JSON.parse(JSON.stringify(value));\n    }\n\n    function loadState() {\n      const raw = localStorage.getItem(STORAGE_KEY);\n      if (!raw) return clone(seed);\n      try {\n        return { ...clone(seed), ...JSON.parse(raw) };\n      } catch {\n        return clone(seed);\n      }\n    }\n\n    function saveState(message) {\n      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));\n      if (message) toast(message);\n      render();\n    }\n\n    function shekel(value) {\n      return new Intl.NumberFormat('he-IL', { style: 'currency', currency: 'ILS', maximumFractionDigits: 0 }).format(value || 0);\n    }\n\n    function today() {\n      return new Date().toISOString().slice(0, 10);\n    }\n\n    function nextId(prefix, list) {\n      return prefix + (Date.now().toString(36) + list.length.toString(36));\n    }\n\n    function customer(id) {\n      return state.customers.find((item) => item.id === id);\n    }\n\n    function product(id) {\n      return state.products.find((item) => item.id === id);\n    }\n\n    function orderTotal(order) {\n      return order.items.reduce((sum, item) => sum + Number(item.quantity || 0) * Number(item.unitPrice || 0), 0);\n    }\n\n    function priceFor(customerId, productId) {\n      const base = product(productId)?.basePrice || 0;\n      const override = state.prices.find((item) => item.customerId === customerId && item.productId === productId);\n      if (!override) return base;\n      const custom = Number(override.customPrice || 0);\n      const start = custom > 0 ? custom : base;\n      return Math.round(start * (1 - Number(override.discountPercent || 0) / 100));\n    }\n\n    function statusLabel(value) {\n      const labels = {\n        new: 'חדשה',\n        confirmed: 'מאושרת',\n        delivered: 'סופקה',\n        cancelled: 'בוטלה',\n        pending_online_payment: 'ממתין לתשלום',\n        cash_on_delivery: 'מזומן לשליח',\n        paid_cash: 'שולם במזומן',\n        paid_online: 'שולם אונליין',\n        failed: 'נכשל'\n      };\n      return labels[value] || value;\n    }\n\n    function statusClass(value) {\n      if (['paid_online', 'paid_cash', 'delivered', 'confirmed'].includes(value)) return 'ok';\n      if (['cash_on_delivery', 'pending_online_payment', 'new'].includes(value)) return 'warn';\n      if (['failed', 'cancelled'].includes(value)) return 'danger';\n      return '';\n    }\n\n    function toast(message) {\n      const node = document.getElementById('toast');\n      node.textContent = message;\n      node.classList.remove('hidden');\n      window.clearTimeout(toast.timer);\n      toast.timer = window.setTimeout(() => node.classList.add('hidden'), 2400);\n    }\n\n    function renderNav() {\n      const nav = document.getElementById('nav');\n      nav.innerHTML = tabs.map(([id, label]) => `<button class=\"nav-button ${id === currentTab ? 'active' : ''}\" data-tab=\"${id}\" type=\"button\">${label}</button>`).join('');\n      nav.querySelectorAll('button').forEach((button) => {\n        button.addEventListener('click', () => {\n          currentTab = button.dataset.tab;\n          render();\n        });\n      });\n    }\n\n    function render() {\n      renderNav();\n      const [, title, subtitle] = tabs.find(([id]) => id === currentTab);\n      document.getElementById('pageTitle').textContent = title;\n      document.getElementById('pageSubtitle').textContent = subtitle;\n      const view = document.getElementById('view');\n      view.innerHTML = ({\n        dashboard: dashboardView,\n        customers: customersView,\n        products: productsView,\n        pricing: pricingView,\n        orders: ordersView,\n        deliveries: deliveriesView,\n        settings: settingsView\n      })[currentTab]();\n      bindView();\n    }\n\n    function dashboardView() {\n      const openOrders = state.orders.filter((order) => order.status !== 'delivered' && order.status !== 'cancelled');\n      const cash = state.orders.filter((order) => order.paymentStatus === 'cash_on_delivery');\n      const revenue = state.orders.filter((order) => ['paid_online', 'paid_cash'].includes(order.paymentStatus)).reduce((sum, order) => sum + orderTotal(order), 0);\n      return `\n        <div class=\"grid metrics\">\n          <div class=\"metric\"><span>לקוחות פעילים</span><strong>${state.customers.filter((item) => item.active).length}</strong></div>\n          <div class=\"metric\"><span>מוצרים פעילים</span><strong>${state.products.filter((item) => item.active).length}</strong></div>\n          <div class=\"metric\"><span>הזמנות פתוחות</span><strong>${openOrders.length}</strong></div>\n          <div class=\"metric\"><span>שולם בדמו</span><strong>${shekel(revenue)}</strong></div>\n        </div>\n        <div class=\"split\">\n          <div class=\"panel\">\n            <div class=\"panel-head\"><h2>הזמנות קרובות</h2><button class=\"button primary\" data-goto=\"orders\" type=\"button\">הזמנה חדשה</button></div>\n            ${ordersTable(state.orders.slice().sort((a, b) => (a.deliveryDate || '').localeCompare(b.deliveryDate || '')).slice(0, 6))}\n          </div>\n          <div class=\"panel\">\n            <div class=\"panel-head\"><h2>תשומת לב</h2></div>\n            <div class=\"list\">\n              <div class=\"delivery-card cash\"><strong>${cash.length} הזמנות מזומן לשליח</strong><br><span class=\"muted\">צריך לוודא גבייה וסימון ידני.</span></div>\n              <div class=\"delivery-card\"><strong>Grow / משולם עדיין stub</strong><br><span class=\"muted\">כפתור קישור תשלום יוצר URL בדיקה בלבד.</span></div>\n              <div class=\"delivery-card\"><strong>פורטל לקוח בשלב הבא</strong><br><span class=\"muted\">טלפון + סיסמה והחלפת סיסמה ראשונה כבר מוגדרים באפיון.</span></div>\n            </div>\n          </div>\n        </div>`;\n    }\n\n    function customersView() {\n      return `\n        <div class=\"split\">\n          <div class=\"panel\">\n            <div class=\"panel-head\"><h2>לקוחות</h2><input id=\"customerSearch\" placeholder=\"חיפוש לפי שם, טלפון או עיר\"></div>\n            <div class=\"table-wrap\">${customersTable(state.customers)}</div>\n          </div>\n          <form class=\"panel form-grid\" id=\"customerForm\">\n            <div class=\"field full\"><h2>לקוח חדש / עריכה</h2></div>\n            ${hiddenId('customerId')}\n            ${field('שם', 'customerName')}\n            ${field('טלפון', 'customerPhone')}\n            ${field('כתובת', 'customerAddress')}\n            ${field('עיר', 'customerCity')}\n            ${field('אזור', 'customerArea')}\n            <div class=\"field\"><label>פעיל</label><select id=\"customerActive\"><option value=\"true\">כן</option><option value=\"false\">לא</option></select></div>\n            ${area('הערות משלוח', 'customerDeliveryNotes')}\n            ${area('הערות פנימיות', 'customerInternalNotes')}\n            <div class=\"field full toolbar\"><button class=\"button primary\" type=\"submit\">שמירה</button><button class=\"button ghost\" id=\"clearCustomer\" type=\"button\">ניקוי</button></div>\n          </form>\n        </div>`;\n    }\n\n    function customersTable(rows) {\n      return `<table><thead><tr><th>שם</th><th>טלפון</th><th>עיר/אזור</th><th>סטטוס</th><th>פעולות</th></tr></thead><tbody>${rows.map((item) => `\n        <tr>\n          <td><strong>${item.name}</strong><br><span class=\"muted\">${item.address}</span></td>\n          <td class=\"nowrap\">${item.phone}</td>\n          <td>${item.city}<br><span class=\"muted\">${item.area}</span></td>\n          <td><span class=\"status ${item.active ? 'ok' : 'danger'}\">${item.active ? 'פעיל' : 'לא פעיל'}</span></td>\n          <td><div class=\"row-actions\"><button class=\"mini\" data-edit-customer=\"${item.id}\" type=\"button\">עריכה</button><button class=\"mini\" data-order-customer=\"${item.id}\" type=\"button\">הזמנה</button></div></td>\n        </tr>`).join('')}</tbody></table>`;\n    }\n\n    function productsView() {\n      return `\n        <div class=\"split\">\n          <div class=\"panel\">\n            <div class=\"panel-head\"><h2>מוצרים</h2></div>\n            <div class=\"table-wrap\">${productsTable()}</div>\n          </div>\n          <form class=\"panel form-grid\" id=\"productForm\">\n            <div class=\"field full\"><h2>מוצר חדש / עריכה</h2></div>\n            ${hiddenId('productId')}\n            ${field('מותג', 'productBrand')}\n            ${field('סדרה', 'productSeries')}\n            ${field('חיה', 'productAnimal')}\n            ${field('שלב חיים', 'productStage')}\n            ${field('טעם', 'productFlavor')}\n            ${field('משקל ק\"ג', 'productWeight', 'number')}\n            ${field('שם תצוגה', 'productName')}\n            ${field('מחיר בסיס', 'productPrice', 'number')}\n            <div class=\"field\"><label>פעיל</label><select id=\"productActive\"><option value=\"true\">כן</option><option value=\"false\">לא</option></select></div>\n            <div class=\"field full toolbar\"><button class=\"button primary\" type=\"submit\">שמירה</button><button class=\"button ghost\" id=\"clearProduct\" type=\"button\">ניקוי</button></div>\n          </form>\n        </div>`;\n    }\n\n    function productsTable() {\n      return `<table><thead><tr><th>מוצר</th><th>מאפיינים</th><th>מחיר בסיס</th><th>סטטוס</th><th>פעולות</th></tr></thead><tbody>${state.products.map((item) => `\n        <tr>\n          <td><strong>${item.name}</strong><br><span class=\"muted\">${item.brand} ${item.series}</span></td>\n          <td>${item.animal} / ${item.stage}<br><span class=\"muted\">${item.flavor}, ${item.weightKg} ק\"ג</span></td>\n          <td>${shekel(item.basePrice)}</td>\n          <td><span class=\"status ${item.active ? 'ok' : 'danger'}\">${item.active ? 'פעיל' : 'לא פעיל'}</span></td>\n          <td><button class=\"mini\" data-edit-product=\"${item.id}\" type=\"button\">עריכה</button></td>\n        </tr>`).join('')}</tbody></table>`;\n    }\n\n    function pricingView() {\n      return `\n        <div class=\"split\">\n          <div class=\"panel\">\n            <div class=\"panel-head\"><h2>מחירים אישיים</h2></div>\n            <div class=\"table-wrap\"><table><thead><tr><th>לקוח</th><th>מוצר</th><th>מחיר אישי</th><th>הנחה</th><th>מחיר להזמנה</th><th>פעולות</th></tr></thead><tbody>${state.prices.map((item) => `\n              <tr>\n                <td>${customer(item.customerId)?.name || '-'}</td>\n                <td>${product(item.productId)?.name || '-'}</td>\n                <td>${Number(item.customPrice || 0) > 0 ? shekel(item.customPrice) : '-'}</td>\n                <td>${item.discountPercent || 0}%</td>\n                <td><strong>${shekel(priceFor(item.customerId, item.productId))}</strong></td>\n                <td><button class=\"mini\" data-delete-price=\"${item.id}\" type=\"button\">מחיקה</button></td>\n              </tr>`).join('')}</tbody></table></div>\n          </div>\n          <form class=\"panel form-grid\" id=\"priceForm\">\n            <div class=\"field full\"><h2>הוספת כלל מחיר</h2></div>\n            <div class=\"field full\"><label>לקוח</label>${customerSelect('priceCustomer')}</div>\n            <div class=\"field full\"><label>מוצר</label>${productSelect('priceProduct')}</div>\n            ${field('מחיר אישי', 'customPrice', 'number')}\n            ${field('הנחה %', 'discountPercent', 'number')}\n            ${area('הערות', 'priceNotes')}\n            <div class=\"field full toolbar\"><button class=\"button primary\" type=\"submit\">שמירה</button></div>\n          </form>\n        </div>`;\n    }\n\n    function ordersView() {\n      return `\n        <div class=\"split\">\n          <div class=\"panel\">\n            <div class=\"panel-head\"><h2>הזמנות</h2></div>\n            <div class=\"filters\">\n              <select id=\"orderPaymentFilter\"><option value=\"\">כל התשלומים</option><option value=\"pending_online_payment\">ממתין לתשלום</option><option value=\"cash_on_delivery\">מזומן לשליח</option><option value=\"paid_online\">שולם אונליין</option><option value=\"paid_cash\">שולם במזומן</option></select>\n              <input id=\"orderAreaFilter\" placeholder=\"סינון עיר/אזור\">\n              <input id=\"orderDateFilter\" type=\"date\">\n              <button class=\"button ghost\" id=\"clearOrderFilters\" type=\"button\">ניקוי</button>\n            </div>\n            <div id=\"ordersTable\">${ordersTable(state.orders)}</div>\n          </div>\n          <form class=\"panel order-builder\" id=\"orderForm\">\n            <h2>הזמנה ידנית</h2>\n            <div class=\"field\"><label>לקוח</label>${customerSelect('orderCustomer')}</div>\n            <div id=\"orderItems\"></div>\n            <button class=\"button ghost\" id=\"addOrderItem\" type=\"button\">הוספת מוצר</button>\n            <div class=\"form-grid\">\n              <div class=\"field\"><label>תאריך אספקה</label><input id=\"deliveryDate\" type=\"date\" value=\"${today()}\"></div>\n              <div class=\"field\"><label>סטטוס תשלום</label><select id=\"paymentStatus\"><option value=\"pending_online_payment\">ממתין לתשלום</option><option value=\"cash_on_delivery\">מזומן לשליח</option><option value=\"paid_cash\">שולם במזומן</option><option value=\"paid_online\">שולם אונליין</option></select></div>\n            </div>\n            ${area('הערות', 'orderNotes')}\n            <div class=\"total-line\"><span>סה\"כ</span><span id=\"orderTotal\">₪0</span></div>\n            <button class=\"button primary\" type=\"submit\">יצירת הזמנה</button>\n          </form>\n        </div>`;\n    }\n\n    function ordersTable(rows) {\n      if (!rows.length) return '<div class=\"empty\">אין הזמנות להצגה</div>';\n      return `<div class=\"table-wrap\"><table><thead><tr><th>מספר</th><th>לקוח</th><th>אספקה</th><th>פריטים</th><th>סה\"כ</th><th>תשלום</th><th>פעולות</th></tr></thead><tbody>${rows.map((order) => {\n        const c = customer(order.customerId);\n        return `<tr>\n          <td><strong>${order.id}</strong><br><span class=\"muted\">${order.createdAt}</span></td>\n          <td>${c?.name || '-'}<br><span class=\"muted\">${c ? `${c.city} / ${c.area}` : ''}</span></td>\n          <td>${order.deliveryDate || '-'}<br><span class=\"status ${statusClass(order.status)}\">${statusLabel(order.status)}</span></td>\n          <td>${order.items.map((item) => `${product(item.productId)?.name || '-'} × ${item.quantity}`).join('<br>')}</td>\n          <td><strong>${shekel(orderTotal(order))}</strong></td>\n          <td><span class=\"status ${statusClass(order.paymentStatus)}\">${statusLabel(order.paymentStatus)}</span></td>\n          <td><div class=\"row-actions\"><button class=\"mini\" data-pay-link=\"${order.id}\" type=\"button\">קישור תשלום</button><button class=\"mini\" data-mark-paid=\"${order.id}\" type=\"button\">סמן שולם</button><button class=\"mini\" data-delivered=\"${order.id}\" type=\"button\">סופק</button></div></td>\n        </tr>`;\n      }).join('')}</tbody></table></div>`;\n    }\n\n    function deliveriesView() {\n      const rows = state.orders.slice().sort((a, b) => (a.deliveryDate || '').localeCompare(b.deliveryDate || ''));\n      return `\n        <div class=\"panel\">\n          <div class=\"panel-head\"><h2>משלוחים קרובים</h2><input id=\"deliveryFilter\" placeholder=\"סינון לפי עיר, אזור או לקוח\"></div>\n          <div class=\"list\" id=\"deliveryList\">${deliveryCards(rows)}</div>\n        </div>`;\n    }\n\n    function deliveryCards(rows) {\n      if (!rows.length) return '<div class=\"empty\">אין משלוחים להצגה</div>';\n      return rows.map((order) => {\n        const c = customer(order.customerId);\n        const cash = order.paymentStatus === 'cash_on_delivery';\n        return `<article class=\"delivery-card ${cash ? 'cash' : ''}\">\n          <strong>${order.deliveryDate || 'ללא תאריך'} | ${c?.name || '-'}</strong>\n          <p class=\"muted\">${c?.address || ''}, ${c?.city || ''} | ${c?.area || ''}</p>\n          <p>${order.items.map((item) => `${product(item.productId)?.name || '-'} × ${item.quantity}`).join('<br>')}</p>\n          <p><span class=\"status ${statusClass(order.paymentStatus)}\">${statusLabel(order.paymentStatus)}</span> <strong>${shekel(orderTotal(order))}</strong></p>\n          ${order.notes ? `<p class=\"muted\">${order.notes}</p>` : ''}\n        </article>`;\n      }).join('');\n    }\n\n    function settingsView() {\n      return `\n        <div class=\"grid\">\n          <div class=\"panel\"><div class=\"panel-head\"><h2>סטטוסים חיצוניים</h2></div>\n            <div class=\"grid metrics\">\n              <div class=\"metric\"><span>Grow / משולם</span><strong>Stub</strong></div>\n              <div class=\"metric\"><span>לינק סיסמה ראשוני</span><strong>TBD</strong></div>\n              <div class=\"metric\"><span>ייבוא לקוחות</span><strong>TBD</strong></div>\n              <div class=\"metric\"><span>חשבוניות מזומן</span><strong>TBD</strong></div>\n            </div>\n          </div>\n          <div class=\"panel\"><h2>כללי אבטחה שנקבעו</h2><p class=\"muted\">לקוחות נוצרים רק על ידי בעל העסק. בפורטל הלקוח העתידי תהיה כניסה עם טלפון וסיסמה, סיסמה זמנית/לינק ראשוני, והחלפת סיסמה חובה בכניסה הראשונה.</p></div>\n        </div>`;\n    }\n\n    function field(labelText, id, type = 'text') {\n      return `<div class=\"field\"><label>${labelText}</label><input id=\"${id}\" type=\"${type}\"></div>`;\n    }\n\n    function area(labelText, id) {\n      return `<div class=\"field full\"><label>${labelText}</label><textarea id=\"${id}\"></textarea></div>`;\n    }\n\n    function hiddenId(id) {\n      return `<input id=\"${id}\" type=\"hidden\">`;\n    }\n\n    function customerSelect(id) {\n      return `<select id=\"${id}\">${state.customers.filter((item) => item.active).map((item) => `<option value=\"${item.id}\">${item.name} | ${item.phone}</option>`).join('')}</select>`;\n    }\n\n    function productSelect(id) {\n      return `<select id=\"${id}\">${state.products.filter((item) => item.active).map((item) => `<option value=\"${item.id}\">${item.name} | ${shekel(item.basePrice)}</option>`).join('')}</select>`;\n    }\n\n    function bindView() {\n      document.querySelectorAll('[data-goto]').forEach((button) => button.addEventListener('click', () => { currentTab = button.dataset.goto; render(); }));\n      bindCustomers();\n      bindProducts();\n      bindPricing();\n      bindOrders();\n      bindDeliveries();\n    }\n\n    function bindCustomers() {\n      const form = document.getElementById('customerForm');\n      if (!form) return;\n      document.getElementById('customerSearch').addEventListener('input', (event) => {\n        const q = event.target.value.trim().toLowerCase();\n        const rows = state.customers.filter((item) => [item.name, item.phone, item.city, item.area].join(' ').toLowerCase().includes(q));\n        document.querySelector('.table-wrap').innerHTML = customersTable(rows);\n        bindCustomerRows();\n      });\n      bindCustomerRows();\n      document.getElementById('clearCustomer').addEventListener('click', () => form.reset());\n      form.addEventListener('submit', (event) => {\n        event.preventDefault();\n        const id = document.getElementById('customerId').value || nextId('c', state.customers);\n        const item = {\n          id,\n          name: value('customerName'),\n          phone: value('customerPhone'),\n          address: value('customerAddress'),\n          city: value('customerCity'),\n          area: value('customerArea'),\n          deliveryNotes: value('customerDeliveryNotes'),\n          internalNotes: value('customerInternalNotes'),\n          active: value('customerActive') === 'true'\n        };\n        if (!item.name || !item.phone) return toast('צריך שם וטלפון ללקוח');\n        upsert(state.customers, item);\n        saveState('לקוח נשמר');\n      });\n    }\n\n    function bindCustomerRows() {\n      document.querySelectorAll('[data-edit-customer]').forEach((button) => button.addEventListener('click', () => fillCustomer(button.dataset.editCustomer)));\n      document.querySelectorAll('[data-order-customer]').forEach((button) => button.addEventListener('click', () => { state.selected.customerId = button.dataset.orderCustomer; currentTab = 'orders'; render(); }));\n    }\n\n    function fillCustomer(id) {\n      const item = customer(id);\n      if (!item) return;\n      setValue('customerId', item.id);\n      setValue('customerName', item.name);\n      setValue('customerPhone', item.phone);\n      setValue('customerAddress', item.address);\n      setValue('customerCity', item.city);\n      setValue('customerArea', item.area);\n      setValue('customerDeliveryNotes', item.deliveryNotes);\n      setValue('customerInternalNotes', item.internalNotes);\n      setValue('customerActive', String(item.active));\n    }\n\n    function bindProducts() {\n      const form = document.getElementById('productForm');\n      if (!form) return;\n      document.querySelectorAll('[data-edit-product]').forEach((button) => button.addEventListener('click', () => fillProduct(button.dataset.editProduct)));\n      document.getElementById('clearProduct').addEventListener('click', () => form.reset());\n      form.addEventListener('submit', (event) => {\n        event.preventDefault();\n        const id = value('productId') || nextId('p', state.products);\n        const item = {\n          id,\n          brand: value('productBrand'),\n          series: value('productSeries'),\n          animal: value('productAnimal'),\n          stage: value('productStage'),\n          flavor: value('productFlavor'),\n          weightKg: Number(value('productWeight') || 0),\n          name: value('productName'),\n          basePrice: Number(value('productPrice') || 0),\n          active: value('productActive') === 'true'\n        };\n        if (!item.name || !item.basePrice) return toast('צריך שם מוצר ומחיר בסיס');\n        upsert(state.products, item);\n        saveState('מוצר נשמר');\n      });\n    }\n\n    function fillProduct(id) {\n      const item = product(id);\n      if (!item) return;\n      setValue('productId', item.id);\n      setValue('productBrand', item.brand);\n      setValue('productSeries', item.series);\n      setValue('productAnimal', item.animal);\n      setValue('productStage', item.stage);\n      setValue('productFlavor', item.flavor);\n      setValue('productWeight', item.weightKg);\n      setValue('productName', item.name);\n      setValue('productPrice', item.basePrice);\n      setValue('productActive', String(item.active));\n    }\n\n    function bindPricing() {\n      const form = document.getElementById('priceForm');\n      if (!form) return;\n      document.querySelectorAll('[data-delete-price]').forEach((button) => button.addEventListener('click', () => {\n        state.prices = state.prices.filter((item) => item.id !== button.dataset.deletePrice);\n        saveState('כלל מחיר נמחק');\n      }));\n      form.addEventListener('submit', (event) => {\n        event.preventDefault();\n        const item = {\n          id: nextId('cp', state.prices),\n          customerId: value('priceCustomer'),\n          productId: value('priceProduct'),\n          customPrice: Number(value('customPrice') || 0),\n          discountPercent: Number(value('discountPercent') || 0),\n          notes: value('priceNotes')\n        };\n        state.prices = state.prices.filter((price) => !(price.customerId === item.customerId && price.productId === item.productId));\n        state.prices.push(item);\n        saveState('מחיר אישי נשמר');\n      });\n    }\n\n    function bindOrders() {\n      const form = document.getElementById('orderForm');\n      if (!form) return;\n      const customerSelectNode = document.getElementById('orderCustomer');\n      if (state.selected.customerId) customerSelectNode.value = state.selected.customerId;\n      renderOrderItems([{ productId: state.selected.productId || state.products[0]?.id, quantity: 1 }]);\n      customerSelectNode.addEventListener('change', recalcOrder);\n      document.getElementById('addOrderItem').addEventListener('click', () => {\n        const items = readOrderItems();\n        items.push({ productId: state.products[0]?.id, quantity: 1 });\n        renderOrderItems(items);\n      });\n      document.getElementById('clearOrderFilters').addEventListener('click', () => {\n        setValue('orderPaymentFilter', '');\n        setValue('orderAreaFilter', '');\n        setValue('orderDateFilter', '');\n        filterOrders();\n      });\n      ['orderPaymentFilter', 'orderAreaFilter', 'orderDateFilter'].forEach((id) => document.getElementById(id).addEventListener('input', filterOrders));\n      bindOrderActionButtons();\n      form.addEventListener('submit', (event) => {\n        event.preventDefault();\n        const customerId = value('orderCustomer');\n        const items = readOrderItems().map((item) => ({ ...item, unitPrice: priceFor(customerId, item.productId) })).filter((item) => item.productId && item.quantity > 0);\n        if (!items.length) return toast('צריך לפחות פריט אחד');\n        const id = nextId('o', state.orders);\n        const paymentStatus = value('paymentStatus');\n        state.orders.push({\n          id,\n          customerId,\n          createdAt: today(),\n          deliveryDate: value('deliveryDate'),\n          status: paymentStatus === 'paid_online' || paymentStatus === 'paid_cash' ? 'confirmed' : 'new',\n          paymentStatus,\n          source: 'manual',\n          paymentUrl: paymentStatus === 'pending_online_payment' ? `https://pay.example.test/orders/${id}` : '',\n          notes: value('orderNotes'),\n          items\n        });\n        saveState('הזמנה נוצרה');\n      });\n    }\n\n    function renderOrderItems(items) {\n      document.getElementById('orderItems').innerHTML = items.map((item, index) => `\n        <div class=\"item-row\" data-order-row>\n          <div class=\"field\"><label>מוצר</label>${productSelect(`orderProduct${index}`)}</div>\n          <div class=\"field\"><label>כמות</label><input id=\"orderQty${index}\" type=\"number\" min=\"1\" value=\"${item.quantity || 1}\"></div>\n          <button class=\"mini\" data-remove-order-item=\"${index}\" type=\"button\">×</button>\n        </div>`).join('');\n      items.forEach((item, index) => {\n        setValue(`orderProduct${index}`, item.productId);\n        document.getElementById(`orderProduct${index}`).addEventListener('change', recalcOrder);\n        document.getElementById(`orderQty${index}`).addEventListener('input', recalcOrder);\n      });\n      document.querySelectorAll('[data-remove-order-item]').forEach((button) => button.addEventListener('click', () => {\n        const next = readOrderItems().filter((_, index) => index !== Number(button.dataset.removeOrderItem));\n        renderOrderItems(next.length ? next : [{ productId: state.products[0]?.id, quantity: 1 }]);\n      }));\n      recalcOrder();\n    }\n\n    function readOrderItems() {\n      return Array.from(document.querySelectorAll('[data-order-row]')).map((_, index) => ({\n        productId: value(`orderProduct${index}`),\n        quantity: Number(value(`orderQty${index}`) || 0)\n      }));\n    }\n\n    function recalcOrder() {\n      const customerId = value('orderCustomer');\n      const total = readOrderItems().reduce((sum, item) => sum + priceFor(customerId, item.productId) * item.quantity, 0);\n      document.getElementById('orderTotal').textContent = shekel(total);\n    }\n\n    function filterOrders() {\n      const payment = value('orderPaymentFilter');\n      const area = value('orderAreaFilter').toLowerCase();\n      const date = value('orderDateFilter');\n      const rows = state.orders.filter((order) => {\n        const c = customer(order.customerId);\n        const areaText = [c?.city, c?.area, c?.name].join(' ').toLowerCase();\n        return (!payment || order.paymentStatus === payment) && (!area || areaText.includes(area)) && (!date || order.deliveryDate === date);\n      });\n      document.getElementById('ordersTable').innerHTML = ordersTable(rows);\n      bindOrderActionButtons();\n    }\n\n    function bindOrderActionButtons() {\n      document.querySelectorAll('[data-pay-link]').forEach((button) => button.addEventListener('click', () => {\n        const order = state.orders.find((item) => item.id === button.dataset.payLink);\n        if (!order.paymentUrl) order.paymentUrl = `https://pay.example.test/orders/${order.id}`;\n        navigator.clipboard?.writeText(order.paymentUrl);\n        saveState('קישור תשלום דמו נוצר והועתק אם הדפדפן מאפשר');\n      }));\n      document.querySelectorAll('[data-mark-paid]').forEach((button) => button.addEventListener('click', () => {\n        const order = state.orders.find((item) => item.id === button.dataset.markPaid);\n        order.paymentStatus = 'paid_online';\n        order.status = 'confirmed';\n        saveState('הזמנה סומנה כשולמה');\n      }));\n      document.querySelectorAll('[data-delivered]').forEach((button) => button.addEventListener('click', () => {\n        const order = state.orders.find((item) => item.id === button.dataset.delivered);\n        order.status = 'delivered';\n        saveState('הזמנה סומנה כסופקה');\n      }));\n    }\n\n    function bindDeliveries() {\n      const filter = document.getElementById('deliveryFilter');\n      if (!filter) return;\n      filter.addEventListener('input', () => {\n        const q = filter.value.trim().toLowerCase();\n        const rows = state.orders.filter((order) => {\n          const c = customer(order.customerId);\n          return [c?.name, c?.city, c?.area, c?.address].join(' ').toLowerCase().includes(q);\n        });\n        document.getElementById('deliveryList').innerHTML = deliveryCards(rows);\n      });\n    }\n\n    function value(id) {\n      return document.getElementById(id)?.value?.trim() || '';\n    }\n\n    function setValue(id, val) {\n      const node = document.getElementById(id);\n      if (node) node.value = val ?? '';\n    }\n\n    function upsert(list, item) {\n      const index = list.findIndex((existing) => existing.id === item.id);\n      if (index >= 0) list[index] = item;\n      else list.push(item);\n    }\n\n    document.getElementById('exportBtn').addEventListener('click', () => {\n      const blob = new Blob([JSON.stringify(state, null, 2)], { type: 'application/json' });\n      const url = URL.createObjectURL(blob);\n      const link = document.createElement('a');\n      link.href = url;\n      link.download = `drive-dog-demo-${today()}.json`;\n      link.click();\n      URL.revokeObjectURL(url);\n    });\n\n    document.getElementById('resetBtn').addEventListener('click', () => {\n      if (!confirm('לאפס את נתוני הדמו בדפדפן?')) return;\n      state = clone(seed);\n      saveState('הדמו אופס');\n    });\n\n    render();\n  </script>\n</body>\n</html>\n";

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const html = url.pathname.startsWith("/admin")
      ? adminHtml
      : url.pathname.startsWith("/proposal")
        ? proposalHtml
        : questionnaireHtml;

    return new Response(html, {
      headers: {
        "content-type": "text/html; charset=utf-8",
        "cache-control": "public, max-age=300"
      }
    });
  }
};
